\set ON_ERROR_STOP on
BEGIN;
SELECT plan(23);
SELECT public.ensure_phase6_currency_foundations();
SELECT ok(EXISTS (SELECT 1 FROM public.currency_definitions WHERE currency_code='USD' AND status='active'), 'USD active currency exists');
SELECT ok(EXISTS (SELECT 1 FROM public.currency_definitions WHERE currency_code='JPY' AND minor_unit_precision=0), 'JPY zero-minor-unit currency exists');
SELECT ok(NOT EXISTS (SELECT 1 FROM public.financial_accounts WHERE currency_code IS NULL), 'every financial account has a currency');
SELECT ok(EXISTS (SELECT 1 FROM public.currency_clearing_accounts WHERE currency_code='USD'), 'USD clearing accounts exist');
SELECT throws_ok($$ SELECT public.get_active_exchange_rate('USD','USD') $$, 'same-currency rates are not stored', 'same-currency active rate rejected');
SELECT ok((SELECT rate > 0 FROM public.get_active_exchange_rate('USD','GBP')), 'USD/GBP active rate can be retrieved');
SELECT public.get_or_create_financial_account_for_currency('player','00000000-0000-0000-0000-000000000601','USD','operating','FX player USD',true);
UPDATE public.financial_accounts SET current_balance_minor=100000 WHERE owner_type='player' AND owner_id='00000000-0000-0000-0000-000000000601' AND currency_code='USD';
SELECT ok((public.quote_currency_conversion('player','00000000-0000-0000-0000-000000000601','USD','GBP',10000,'phase6-quote-1')).net_destination_amount_minor > 0, 'conversion quote returns net destination amount');
SELECT ok((SELECT quote_expires_at > timezone('utc',now()) FROM public.currency_conversion_quotes WHERE idempotency_key='phase6-quote-1'), 'quote has future expiry');
SELECT public.execute_currency_conversion((SELECT id FROM public.currency_conversion_quotes WHERE idempotency_key='phase6-quote-1'),'phase6-conv-1');
SELECT is((SELECT status::text FROM public.currency_conversion_quotes WHERE idempotency_key='phase6-quote-1'),'completed','quote marked completed');
SELECT ok(EXISTS (SELECT 1 FROM public.currency_conversions WHERE idempotency_key='phase6-conv-1'), 'conversion record exists');
SELECT ok(EXISTS (SELECT 1 FROM public.financial_ledger_entries e JOIN public.financial_transactions t ON t.id=e.transaction_id WHERE t.related_conversion_id=(SELECT id FROM public.currency_conversions WHERE idempotency_key='phase6-conv-1') AND e.currency_code='USD'), 'source-currency ledger entries exist');
SELECT ok(EXISTS (SELECT 1 FROM public.financial_ledger_entries e JOIN public.financial_transactions t ON t.id=e.transaction_id WHERE t.related_conversion_id=(SELECT id FROM public.currency_conversions WHERE idempotency_key='phase6-conv-1') AND e.currency_code='GBP'), 'destination-currency ledger entries exist');
SELECT is((SELECT COUNT(*)::int FROM public.reconcile_currency_conversions() WHERE subject_id=(SELECT id::text FROM public.currency_conversions WHERE idempotency_key='phase6-conv-1')),0,'completed conversion reconciles');
SELECT throws_ok($$ SELECT public.quote_currency_conversion('player','00000000-0000-0000-0000-000000000601','USD','GBP',999999999999,'phase6-too-large') $$, 'insufficient funds', 'insufficient funds rejected');
INSERT INTO public.currency_conversion_quotes(owner_type,owner_id,source_account_id,destination_account_id,source_currency_code,destination_currency_code,source_amount_minor,exchange_rate_id,exchange_rate,gross_destination_amount_minor,fee_amount_minor,net_destination_amount_minor,quote_expires_at,rate_timestamp,idempotency_key) SELECT 'player','00000000-0000-0000-0000-000000000601',src.id,dst.id,'USD','GBP',100,(SELECT id FROM public.exchange_rates WHERE base_currency_code='USD' AND quote_currency_code='GBP' LIMIT 1),0.78,78,1,77,timezone('utc',now())-interval '1 second',timezone('utc',now()),'phase6-expired' FROM public.financial_accounts src, public.financial_accounts dst WHERE src.owner_type='player' AND src.owner_id='00000000-0000-0000-0000-000000000601' AND src.currency_code='USD' AND dst.owner_type='player' AND dst.owner_id='00000000-0000-0000-0000-000000000601' AND dst.currency_code='GBP' LIMIT 1;
SELECT throws_ok($$ SELECT public.execute_currency_conversion((SELECT id FROM public.currency_conversion_quotes WHERE idempotency_key='phase6-expired'),'phase6-expired-conv') $$, 'quote expired', 'expired quote rejected');
SELECT public.reverse_currency_conversion((SELECT id FROM public.currency_conversions WHERE idempotency_key='phase6-conv-1'),'phase6-reversal-1');
SELECT is((SELECT status::text FROM public.currency_conversions WHERE idempotency_key='phase6-conv-1'),'reversed','conversion reversal marks original reversed');
INSERT INTO public.owner_currency_preferences(owner_type,owner_id,reporting_currency_code) VALUES('player','00000000-0000-0000-0000-000000000601','GBP') ON CONFLICT(owner_type,owner_id) DO UPDATE SET reporting_currency_code='GBP';
SELECT ok(EXISTS (SELECT 1 FROM public.multi_currency_balance_summary WHERE owner_type='player' AND owner_id='00000000-0000-0000-0000-000000000601' AND currency_code IN ('USD','GBP')), 'multi-currency balance summary includes player balances');
SELECT ok(EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name='foreign_gig_income_records'), 'foreign gig income model supports retaining local currency without implicit conversion');
INSERT INTO public.realised_currency_gain_losses(owner_type,owner_id,acquisition_amount_minor,acquisition_currency_code,acquisition_reporting_value_minor,conversion_amount_minor,conversion_reporting_value_minor,realised_gain_loss_minor) VALUES('company',NULL,10000,'GBP',12000,10000,12500,500);
SELECT ok(EXISTS (SELECT 1 FROM public.realised_currency_gain_losses WHERE realised_gain_loss_minor=500), 'realised currency gain/loss record supported');
SELECT ok(EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name='international_payroll_contracts'), 'international payroll contract model supported');
INSERT INTO public.foreign_tax_reporting_conversions(original_amount_minor,original_currency_code,tax_reporting_amount_minor,tax_currency_code,exchange_rate_id,applied_rate,rate_timestamp,rate_version) SELECT 10000,'GBP',12820,'USD',id,1.282, effective_at, rate_version FROM public.exchange_rates WHERE base_currency_code='USD' AND quote_currency_code='GBP' LIMIT 1;
SELECT ok(EXISTS (SELECT 1 FROM public.foreign_tax_reporting_conversions WHERE original_currency_code='GBP' AND tax_currency_code='USD'), 'foreign tax reporting conversion preserves original and tax currency');
SELECT ok(EXISTS (SELECT 1 FROM public.admin_currency_controls_view WHERE currency_code='USD'), 'admin rate controls view available');
SELECT ok((SELECT (public.run_currency_scheduled_rate_processing())->>'reserveSnapshots')::int >= 1, 'scheduled rate processing snapshots reserves');
SELECT * FROM finish();
ROLLBACK;
